"use strict";(self.webpackChunkverl_architecture_lectures=self.webpackChunkverl_architecture_lectures||[]).push([["3795"],{799(n){n.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/verl-architecture-lectures/docs/roadmap","label":"L\u1ED9 tr\xecnh h\u1ECDc t\u1EADp (Roadmap)","docId":"roadmap","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_0_alignment_fundamentals","label":"B\xe0i 0: N\u1EC1n t\u1EA3ng Alignment & Thu\u1EADt to\xe1n PPO vs GRPO","docId":"lesson_0_alignment_fundamentals","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_1_distributed_rl_challenges","label":"B\xe0i 1: Th\xe1ch th\u1EE9c H\u1EC7 th\u1ED1ng trong Distributed RLHF","docId":"lesson_1_distributed_rl_challenges","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_2_hybridflow_programming_model","label":"B\xe0i 2: M\xf4 h\xecnh L\u1EADp tr\xecnh HybridFlow & C\u01A1 ch\u1EBF Single-Controller","docId":"lesson_2_hybridflow_programming_model","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_3_hybrid_engine_resharding","label":"B\xe0i 3: 3D-HybridEngine & C\u01A1 ch\u1EBF T\u1EF1 \u0111\u1ED9ng Resharding Tr\u1ECDng s\u1ED1","docId":"lesson_3_hybrid_engine_resharding","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_4_source_code_walkthrough","label":"B\xe0i 4: Kh\u1EA3o s\xe1t M\xe3 ngu\u1ED3n - Chu tr\xecnh hu\u1EA5n luy\u1EC7n PPO & GRPO","docId":"lesson_4_source_code_walkthrough","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_5_inference_engine_integration","label":"B\xe0i 5: T\xedch h\u1EE3p v\xe0 T\u1ED1i \u01B0u h\xf3a Inference Engine (vLLM & SGLang)","docId":"lesson_5_inference_engine_integration","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_6_verifiable_rewards_tool_use","label":"B\xe0i 6: Qu\u1EA3n l\xfd Ph\u1EA7n th\u01B0\u1EDFng Kh\u1EA3 thi & T\u01B0\u01A1ng t\xe1c C\xf4ng c\u1EE5","docId":"lesson_6_verifiable_rewards_tool_use","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_7_performance_tuning_scaling","label":"B\xe0i 7: H\u01B0\u1EDBng d\u1EABn T\u1ED1i \u01B0u Hi\u1EC7u n\u0103ng & M\u1EDF r\u1ED9ng Quy m\xf4 l\u1EDBn","docId":"lesson_7_performance_tuning_scaling","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/lesson_8_toy_rlhf_pipeline","label":"B\xe0i 8: Th\u1EF1c h\xe0nh: T\u1EF1 vi\u1EBFt Toy RLHF Pipeline v\u1EDBi Single-Controller","docId":"lesson_8_toy_rlhf_pipeline","unlisted":false},{"type":"category","label":"case_studies","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/verl-architecture-lectures/docs/case_studies/roadmap_case_studies","label":"L\u1ED9 tr\xecnh Case Studies","docId":"case_studies/roadmap_case_studies","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/case_studies/case_1_tiny_zero_grpo","label":"Case 1: T\xe1i hi\u1EC7n DeepSeek-R1-Zero (TinyZero)","docId":"case_studies/case_1_tiny_zero_grpo","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/case_studies/case_2_split_placement","label":"Case 2: T\u1ED1i \u01B0u ph\u1EA7n c\u1EE9ng v\u1EDBi Split Placement","docId":"case_studies/case_2_split_placement","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/case_studies/case_3_agentic_multiturn","label":"Case 3: Agentic RL \u0111a l\u01B0\u1EE3t v\u1EDBi SGLang","docId":"case_studies/case_3_agentic_multiturn","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/case_studies/case_4_remax_optimization","label":"Case 4: T\u1ED1i \u01B0u h\xf3a ReMax b\u1ECF Critic","docId":"case_studies/case_4_remax_optimization","unlisted":false},{"type":"link","href":"/verl-architecture-lectures/docs/case_studies/case_5_moe_scaling","label":"Case 5: M\u1EDF r\u1ED9ng MoE 671B v\u1EDBi Expert Parallelism","docId":"case_studies/case_5_moe_scaling","unlisted":false}]}]},"docs":{"case_studies/case_1_tiny_zero_grpo":{"id":"case_studies/case_1_tiny_zero_grpo","title":"Case Study 1: T\xe1i hi\u1EC7n DeepSeek-R1-Zero v\u1EDBi GRPO (D\u1EF1 \xe1n TinyZero)","description":"DeepSeek-R1-Zero m\u1EDF ra m\u1ED9t k\u1EF7 nguy\xean m\u1EDBi khi ch\u1EE9ng minh r\u1EB1ng m\u1ED9t m\xf4 h\xecnh ng\xf4n ng\u1EEF c\xf3 th\u1EC3 t\u1EF1 ph\xe1t tri\u1EC3n kh\u1EA3 n\u0103ng l\u1EADp lu\u1EADn ph\u1EE9c t\u1EA1p (Reasoning) th\xf4ng qua H\u1ECDc t\u0103ng c\u01B0\u1EDDng (RL) m\xe0 kh\xf4ng c\u1EA7n b\u1EA5t k\u1EF3 d\u1EEF li\u1EC7u chu\u1ED7i suy ngh\u0129 (Chain of Thought - CoT) n\xe0o do con ng\u01B0\u1EDDi bi\xean so\u1EA1n.","sidebar":"tutorialSidebar"},"case_studies/case_2_split_placement":{"id":"case_studies/case_2_split_placement","title":"Case Study 2: L\u1EADp l\u1ECBch t\u1ED1i \u01B0u ph\u1EA7n c\u1EE9ng v\u1EDBi Split Placement","description":"Khi k\xedch th\u01B0\u1EDBc m\xf4 h\xecnh ng\xf4n ng\u1EEF t\u0103ng l\xean (v\xed d\u1EE5 t\u1EEB 7B sang 70B ho\u1EB7c m\xf4 h\xecnh MoE l\u1EDBn h\u01A1n), vi\u1EC7c colocated (\u0111\u1EB7t chung) c\u1EA3 4 m\xf4 h\xecnh l\xean c\xf9ng m\u1ED9t t\u1EADp GPU s\u1EBD l\u1EADp t\u1EE9c l\xe0m s\u1EADp h\u1EC7 th\u1ED1ng do l\u1ED7i tr\xe0n b\u1ED9 nh\u1EDB VRAM (OOM).","sidebar":"tutorialSidebar"},"case_studies/case_3_agentic_multiturn":{"id":"case_studies/case_3_agentic_multiturn","title":"Case Study 3: Agentic RL - Hu\u1EA5n luy\u1EC7n m\xf4 h\xecnh g\u1ECDi c\xf4ng c\u1EE5 \u0111a l\u01B0\u1EE3t","description":"M\u1ED9t m\xf4 h\xecnh Agent th\xf4ng minh kh\xf4ng ch\u1EC9 tr\u1EA3 l\u1EDDi trong m\u1ED9t l\u01B0\u1EE3t (Single-turn). N\xf3 ph\u1EA3i c\xf3 kh\u1EA3 n\u0103ng suy ngh\u0129, ph\xe1t sinh l\u1EC7nh g\u1ECDi c\xf4ng c\u1EE5 (Tool Calling), t\u1EA1m d\u1EEBng \u0111\u1EC3 nh\u1EADn k\u1EBFt qu\u1EA3 t\u1EEB m\xf4i tr\u01B0\u1EDDng, r\u1ED3i ti\u1EBFp t\u1EE5c suy ngh\u0129 ho\u1EB7c g\u1ECDi c\xf4ng c\u1EE5 kh\xe1c cho t\u1EDBi khi gi\u1EA3i xong b\xe0i to\xe1n.","sidebar":"tutorialSidebar"},"case_studies/case_4_remax_optimization":{"id":"case_studies/case_4_remax_optimization","title":"Case Study 4: Thu\u1EADt to\xe1n ReMax - Gi\u1EA3i ph\xe1p thay th\u1EBF PPO t\u1ED1i \u01B0u VRAM","description":"M\u1EB7c d\xf9 PPO ho\u1EA1t \u0111\u1ED9ng hi\u1EC7u qu\u1EA3, vi\u1EC7c duy tr\xec m\xf4 h\xecnh Critic \u0111\u1EC3 d\u1EF1 \u0111o\xe1n gi\xe1 tr\u1ECB c\u01A1 s\u1EDF (baseline) g\xe2y ti\xeau hao n\u0103ng l\u01B0\u1EE3ng v\xe0 b\u1ED9 nh\u1EDB GPU r\u1EA5t l\u1EDBn (Critic th\u01B0\u1EDDng c\xf3 k\xedch th\u01B0\u1EDBc t\u01B0\u01A1ng \u0111\u01B0\u01A1ng Actor). \u0110\u1EC3 hu\u1EA5n luy\u1EC7n RLHF hi\u1EC7u qu\u1EA3 h\u01A1n tr\xean c\xe1c c\u1EA5u h\xecnh ph\u1EA7n c\u1EE9ng gi\u1EDBi h\u1EA1n, verl t\xedch h\u1EE3p thu\u1EADt to\xe1n ReMax (d\u1EF1a tr\xean b\xe0i b\xe1o \\"ReMax: A Simple, Effective, and Efficient Alternative to PPO\\").","sidebar":"tutorialSidebar"},"case_studies/case_5_moe_scaling":{"id":"case_studies/case_5_moe_scaling","title":"Case Study 5: M\u1EDF r\u1ED9ng m\xf4 h\xecnh MoE 671B v\u1EDBi Expert Parallelism","description":"\u0110\u1EC3 hu\u1EA5n luy\u1EC7n c\xe1c m\xf4 h\xecnh l\xfd lu\u1EADn si\xeau l\u1EDBn nh\u01B0 DeepSeek-R1 ho\u1EB7c DeepSeek-V3 (t\u1ED5ng s\u1ED1 671B tham s\u1ED1, trong \u0111\xf3 37B tham s\u1ED1 k\xedch ho\u1EA1t cho t\u1EEBng token), vi\u1EC7c s\u1EED d\u1EE5ng song song d\u1EEF li\u1EC7u ho\u1EB7c song song tensor truy\u1EC1n th\u1ED1ng s\u1EBD g\u1EB7p th\u1EA5t b\u1EA1i do ngh\u1EBDn b\u0103ng th\xf4ng v\xe0 tr\xe0n b\u1ED9 nh\u1EDB.","sidebar":"tutorialSidebar"},"case_studies/roadmap_case_studies":{"id":"case_studies/roadmap_case_studies","title":"L\u1ED9 tr\xecnh Case Studies Th\u1EF1c chi\u1EBFn v\u1EDBi verl","description":"Ch\xe0o m\u1EEBng b\u1EA1n \u0111\u1EBFn v\u1EDBi ch\u01B0\u01A1ng Case Studies Th\u1EF1c chi\u1EBFn. Sau khi \u0111\xe3 n\u1EAFm v\u1EEFng l\xfd thuy\u1EBFt c\u1ED1t l\xf5i c\u1EE7a th\u01B0 vi\u1EC7n verl (t\u1EEB B\xe0i 0 \u0111\u1EBFn B\xe0i 8), ph\u1EA7n n\xe0y s\u1EBD \u0111\u01B0a b\u1EA1n v\xe0o c\xe1c k\u1ECBch b\u1EA3n th\u1EF1c t\u1EBF khi hu\u1EA5n luy\u1EC7n v\xe0 m\u1EDF r\u1ED9ng quy m\xf4 h\u1EC7 th\u1ED1ng h\u1ECDc t\u0103ng c\u01B0\u1EDDng.","sidebar":"tutorialSidebar"},"lesson_0_alignment_fundamentals":{"id":"lesson_0_alignment_fundamentals","title":"B\xe0i 0: N\u1EC1n t\u1EA3ng Alignment & Thu\u1EADt to\xe1n PPO vs GRPO","description":"\u0110\u1EC3 hi\u1EC3u \u0111\u01B0\u1EE3c l\xfd do t\u1EA1i sao th\u01B0 vi\u1EC7n verl ra \u0111\u1EDDi v\xe0 c\xe1ch n\xf3 t\u1ED1i \u01B0u h\xf3a h\u1EC7 th\u1ED1ng, tr\u01B0\u1EDBc ti\xean ch\xfang ta ph\u1EA3i n\u1EAFm v\u1EEFng n\u1EC1n t\u1EA3ng l\xfd thuy\u1EBFt v\u1EC1 Alignment (C\u0103n ch\u1EC9nh m\xf4 h\xecnh ng\xf4n ng\u1EEF) v\xe0 hai thu\u1EADt to\xe1n h\u1ECDc t\u0103ng c\u01B0\u1EDDng (RL) ph\u1ED5 bi\u1EBFn nh\u1EA5t hi\u1EC7n nay: PPO (Proximal Policy Optimization) v\xe0 GRPO (Group Relative Policy Optimization).","sidebar":"tutorialSidebar"},"lesson_1_distributed_rl_challenges":{"id":"lesson_1_distributed_rl_challenges","title":"B\xe0i 1: Th\xe1ch th\u1EE9c K\u1EF9 thu\u1EADt H\u1EC7 th\u1ED1ng trong Distributed RLHF","description":"Vi\u1EC7c hu\u1EA5n luy\u1EC7n H\u1ECDc t\u0103ng c\u01B0\u1EDDng ph\u1EA3n h\u1ED3i t\u1EEB con ng\u01B0\u1EDDi (RLHF) tr\xean c\xe1c m\xf4 h\xecnh ng\xf4n ng\u1EEF l\u1EDBn (LLM) kh\xf4ng ch\u1EC9 ph\u1EE9c t\u1EA1p v\u1EC1 m\u1EB7t thu\u1EADt to\xe1n m\xe0 c\xf2n l\xe0 m\u1ED9t c\u01A1n \xe1c m\u1ED9ng v\u1EC1 m\u1EB7t k\u1EF9 thu\u1EADt h\u1EC7 th\u1ED1ng (Systems Engineering).","sidebar":"tutorialSidebar"},"lesson_2_hybridflow_programming_model":{"id":"lesson_2_hybridflow_programming_model","title":"B\xe0i 2: M\xf4 h\xecnh L\u1EADp tr\xecnh HybridFlow & C\u01A1 ch\u1EBF Single-Controller","description":"\u0110\u1EC3 gi\u1EA3i quy\u1EBFt b\xe0i to\xe1n ph\u1EE9c t\u1EA1p v\xe0 ngh\u1EBDn b\u1ED9 nh\u1EDB trong hu\u1EA5n luy\u1EC7n RLHF (\u0111\xe3 th\u1EA3o lu\u1EADn \u1EDF B\xe0i 1), verl \xe1p d\u1EE5ng thi\u1EBFt k\u1EBF \u0111\u1ED9t ph\xe1 d\u1EF1a tr\xean b\xe0i b\xe1o HybridFlow. Thi\u1EBFt k\u1EBF n\xe0y \u0111\u1EC1 xu\u1EA5t m\xf4 h\xecnh l\u1EADp tr\xecnh Single-Controller (B\u1ED9 \u0111i\u1EC1u khi\u1EC3n \u0111\u01A1n) gi\xfap \u0111\u01A1n gi\u1EA3n h\xf3a t\u1ED1i \u0111a vi\u1EC7c l\u1EADp tr\xecnh h\u1EC7 th\u1ED1ng ph\xe2n t\xe1n.","sidebar":"tutorialSidebar"},"lesson_3_hybrid_engine_resharding":{"id":"lesson_3_hybrid_engine_resharding","title":"B\xe0i 3: 3D-HybridEngine & C\u01A1 ch\u1EBF T\u1EF1 \u0111\u1ED9ng Resharding Tr\u1ECDng s\u1ED1","description":"M\u1ED9t trong nh\u1EEFng \u0111\xf3ng g\xf3p c\xf4ng ngh\u1EC7 quan tr\u1ECDng nh\u1EA5t c\u1EE7a th\u01B0 vi\u1EC7n verl (\u0111\u01B0\u1EE3c gi\u1EDBi thi\u1EC7u trong b\xe0i b\xe1o HybridFlow) l\xe0 3D-HybridEngine. \u0110\xe2y l\xe0 gi\u1EA3i ph\xe1p x\u1EED l\xfd tri\u1EC7t \u0111\u1EC3 s\u1EF1 b\u1EA5t t\u01B0\u01A1ng x\u1EE9ng v\u1EC1 chi\u1EBFn l\u01B0\u1EE3c song song h\xf3a gi\u1EEFa hai pha Rollout (Generation) v\xe0 Update (Training) m\xe0 ch\xfang ta \u0111\xe3 \u0111\u1EB7t v\u1EA5n \u0111\u1EC1 \u1EDF B\xe0i 1.","sidebar":"tutorialSidebar"},"lesson_4_source_code_walkthrough":{"id":"lesson_4_source_code_walkthrough","title":"B\xe0i 4: Kh\u1EA3o s\xe1t M\xe3 ngu\u1ED3n - Chu tr\xecnh hu\u1EA5n luy\u1EC7n PPO & GRPO","description":"\u0110\u1EC3 hi\u1EC3u r\xf5 c\xe1ch verl bi\u1EBFn c\xe1c kh\xe1i ni\u1EC7m l\xfd thuy\u1EBFt th\xe0nh m\u1ED9t h\u1EC7 th\u1ED1ng ph\xe2n t\xe1n ch\u1EA1y \u1ED5n \u0111\u1ECBnh, ch\xfang ta s\u1EBD c\xf9ng l\u1EA7n v\u1EBFt (walkthrough) m\xe3 ngu\u1ED3n c\u1ED1t l\xf5i c\u1EE7a th\u01B0 vi\u1EC7n. Ti\xeau \u0111i\u1EC3m ph\xe2n t\xedch l\xe0 l\u1EDBp RayPPOTrainer n\u1EB1m trong file verl/trainer/ppo/ray_trainer.py.","sidebar":"tutorialSidebar"},"lesson_5_inference_engine_integration":{"id":"lesson_5_inference_engine_integration","title":"B\xe0i 5: T\xedch h\u1EE3p v\xe0 T\u1ED1i \u01B0u h\xf3a Inference Engine (vLLM & SGLang)","description":"Trong pha sinh m\u1EABu (Rollout), t\u1ED1c \u0111\u1ED9 v\xe0 hi\u1EC7u su\u1EA5t gi\u1EA3i m\xe3 \u0111\xf3ng vai tr\xf2 quy\u1EBFt \u0111\u1ECBnh \u0111\u1EBFn 60-80% th\u1EDDi gian ch\u1EA1y c\u1EE7a c\u1EA3 pipeline RLHF. Thay v\xec t\u1EF1 vi\u1EBFt h\xe0m sinh m\u1EABu b\u1EB1ng PyTorch th\xf4 s\u01A1 (v\u1ED1n r\u1EA5t ch\u1EADm v\xe0 t\u1ED1n b\u1ED9 nh\u1EDB), verl t\xedch h\u1EE3p tr\u1EF1c ti\u1EBFp c\xe1c c\xf4ng ngh\u1EC7 suy lu\u1EADn m\u1EA1nh m\u1EBD nh\u1EA5t hi\u1EC7n nay l\xe0 vLLM v\xe0 SGLang.","sidebar":"tutorialSidebar"},"lesson_6_verifiable_rewards_tool_use":{"id":"lesson_6_verifiable_rewards_tool_use","title":"B\xe0i 6: Qu\u1EA3n l\xfd Ph\u1EA7n th\u01B0\u1EDFng Kh\u1EA3 thi & T\u01B0\u01A1ng t\xe1c C\xf4ng c\u1EE5 (Rule-based & Sandbox)","description":"Trong hu\u1EA5n luy\u1EC7n RLHF truy\u1EC1n th\u1ED1ng cho c\xe1c t\xe1c v\u1EE5 v\u0103n h\u1ECDc ho\u1EB7c h\u1ED9i tho\u1EA1i, ng\u01B0\u1EDDi ta th\u01B0\u1EDDng d\xf9ng m\u1ED9t m\xf4 h\xecnh ph\u1EA7n th\u01B0\u1EDFng (Reward Model - RM) d\u1EA1ng m\u1EA1ng neural \u0111\u1EC3 ch\u1EA5m \u0111i\u1EC3m. Tuy nhi\xean, m\xf4 h\xecnh RM r\u1EA5t d\u1EC5 b\u1ECB Actor \\"\u0111\xe1nh l\u1EEBa\\" (Reward Hacking) \u2013 Actor t\u1EF1 t\xecm ra c\xe1c c\u1EE5m t\u1EEB hoa m\u1EF9 ho\u1EB7c khu\xf4n m\u1EABu l\xe0m v\u1EEBa l\xf2ng RM m\xe0 kh\xf4ng th\u1EF1c s\u1EF1 tr\u1EA3 l\u1EDDi \u0111\xfang c\xe2u h\u1ECFi.","sidebar":"tutorialSidebar"},"lesson_7_performance_tuning_scaling":{"id":"lesson_7_performance_tuning_scaling","title":"B\xe0i 7: H\u01B0\u1EDBng d\u1EABn T\u1ED1i \u01B0u Hi\u1EC7u n\u0103ng & M\u1EDF r\u1ED9ng Quy m\xf4 l\u1EDBn","description":"Hu\u1EA5n luy\u1EC7n c\xe1c m\xf4 h\xecnh ng\xf4n ng\u1EEF l\u1EDBn b\u1EB1ng h\u1ECDc t\u0103ng c\u01B0\u1EDDng (RLHF) l\xe0 m\u1ED9t t\xe1c v\u1EE5 ti\xeau t\u1ED1n c\u1EF1c k\u1EF3 nhi\u1EC1u t\xe0i nguy\xean t\xednh to\xe1n. \u0110\u1EC3 v\u1EADn h\xe0nh h\u1EC7 th\u1ED1ng \u1ED5n \u0111\u1ECBnh tr\xean h\xe0ng ch\u1EE5c ho\u1EB7c h\xe0ng tr\u0103m GPU m\xe0 kh\xf4ng b\u1ECB l\u1ED7i tr\xe0n b\u1ED9 nh\u1EDB (OOM) hay ngh\u1EBDn m\u1EA1ng, ch\xfang ta c\u1EA7n n\u1EAFm v\u1EEFng c\xe1c k\u1EF9 thu\u1EADt t\u1ED1i \u01B0u h\xf3a hi\u1EC7u n\u0103ng chuy\xean s\xe2u c\u1EE7a verl.","sidebar":"tutorialSidebar"},"lesson_8_toy_rlhf_pipeline":{"id":"lesson_8_toy_rlhf_pipeline","title":"B\xe0i 8: Th\u1EF1c h\xe0nh: T\u1EF1 vi\u1EBFt Toy RLHF Pipeline v\u1EDBi Single-Controller","description":"Kh\xf4ng c\xf3 c\xe1ch n\xe0o hi\u1EC3u s\xe2u s\u1EAFc ki\u1EBFn tr\xfac h\u1EC7 th\u1ED1ng c\u1EE7a verl t\u1ED1t h\u01A1n vi\u1EC7c t\u1EF1 tay x\xe2y d\u1EF1ng m\u1ED9t phi\xean b\u1EA3n thu nh\u1ECF (Toy Implementation) c\u1EE7a n\xf3.","sidebar":"tutorialSidebar"},"roadmap":{"id":"roadmap","title":"L\u1ED9 tr\xecnh h\u1ECDc t\u1EADp & Ph\xe2n t\xedch c\u1EA5u tr\xfac th\u01B0 vi\u1EC7n verl","description":"Ch\xe0o m\u1EEBng b\u1EA1n \u0111\u1EBFn v\u1EDBi t\xe0i li\u1EC7u ph\xe2n t\xedch chuy\xean s\xe2u v\u1EC1 ki\u1EBFn tr\xfac v\xe0 hi\u1EC7n th\u1EF1c c\u1EE7a th\u01B0 vi\u1EC7n verl (Volcano Engine Reinforcement Learning for LLMs) do ByteDance Seed team ph\xe1t tri\u1EC3n v\xe0 m\xe3 ngu\u1ED3n m\u1EDF h\xf3a.","sidebar":"tutorialSidebar"}}}}')}}]);